"use client";

import React, { useState, useMemo } from 'react';
import { DrumRoll } from '@/components/ui/DrumRoll';
import { MatrixLayout } from '@/components/layout/MatrixLayout';
import { AxisItem } from '@/types/matrix';

// --- データ定義 ---
const clients: AxisItem[] = [
  { id: 'c1', label: '株式会社 鈴木商店', subLabel: 'ID: 1001' },
  { id: 'c2', label: '合同会社 テック', subLabel: 'ID: 1002' },
  { id: 'c3', label: '佐藤 健太（個人）', subLabel: 'ID: 2005' },
  { id: 'c4', label: '山田不動産', subLabel: 'ID: 3040' },
  { id: 'c5', label: '東京コンサルティング', subLabel: 'ID: 5001' },
];

const periods: AxisItem[] = [
  { id: 'perm', label: '永続', subLabel: 'PERMANENT', type: 'special' },
  { id: 'r6', label: 'R6', subLabel: '2024' },
  { id: 'r5', label: 'R5', subLabel: '2023' },
  { id: 'r4', label: 'R4', subLabel: '2022' },
];

const mockDb: Record<string, { title: string, filled: boolean }[]> = {
  'c1-r6': [{ title: 'R6 試算表（上期）', filled: true }, { title: 'R6 試算表（下期）', filled: false }],
  'c1-r5': [{ title: '決算報告書', filled: true }, { title: '総勘定元帳', filled: true }, { title: '法人税申告書', filled: true }, { title: '消費税申告書', filled: true }],
  'c2-r6': [{ title: 'R6 試算表（上期）', filled: false }, { title: 'R6 試算表（下期）', filled: false }],
  'c1-perm': [{ title: '定款', filled: true }, { title: '登記簿謄本', filled: true }, { title: '税務署届出控え', filled: false }]
};

const defaultTemplates = {
  year: [{ title: '決算報告書', filled: false }, { title: '総勘定元帳', filled: false }, { title: '法人税申告書', filled: false }, { title: '消費税申告書', filled: false }],
  perm: [{ title: '定款', filled: false }, { title: '履歴事項全部証明書', filled: false }]
};

// --- メインコンポーネント ---
export default function DocuGridPage() {
  const [clientId, setClientId] = useState(clients[0].id);
  const [periodId, setPeriodId] = useState(periods[1].id);

  const currentData = useMemo(() => {
    const key = `${clientId}-${periodId}`;
    if (mockDb[key]) return mockDb[key];
    return periodId === 'perm' ? defaultTemplates.perm : defaultTemplates.year;
  }, [clientId, periodId]);

  const progress = useMemo(() => {
    if (!currentData.length) return 0;
    const filled = currentData.filter(d => d.filled).length;
    return Math.round((filled / currentData.length) * 100);
  }, [currentData]);

  const selectedClient = clients.find(c => c.id === clientId);
  const selectedPeriod = periods.find(p => p.id === periodId);

  return (
    <MatrixLayout
      topDrum={<DrumRoll items={clients} direction="horizontal" selectedId={clientId} onSelect={setClientId} />}
      leftDrum={<DrumRoll items={periods} direction="vertical" selectedId={periodId} onSelect={setPeriodId} />}
      headerTitle={
        <div>
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{selectedClient?.label}</div>
          <div className="text-xl font-bold text-slate-800 leading-tight flex items-center gap-2">
            <span className={periodId === 'perm' ? 'text-yellow-500' : 'text-blue-600'}>{selectedPeriod?.label}</span>
            <span>{periodId === 'perm' ? '永久保存ドキュメント' : '確定申告・決算資料'}</span>
          </div>
        </div>
      }
      progress={progress}
      progressColor={periodId === 'perm' ? 'text-yellow-500' : 'text-blue-600'}
    >
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 animate-[fadeInUp_0.4s_ease-out]">
        {currentData.map((item, idx) => (
          <div key={idx} className={`relative h-40 rounded-2xl p-5 flex flex-col justify-between transition-all cursor-pointer group ${item.filled ? 'bg-white shadow-sm border-l-4 border-indigo-500 hover:shadow-lg hover:scale-105' : 'bg-slate-50 border-2 border-dashed border-slate-300 hover:bg-white hover:border-blue-400'}`}>
            {item.filled ? (
              <>
                <div className="flex justify-between items-start"><span className="text-[10px] font-bold bg-slate-100 text-slate-500 px-2 py-1 rounded uppercase tracking-wider">PDF</span><div className="w-5 h-5 rounded-full bg-green-500 flex items-center justify-center text-white text-xs">✓</div></div>
                <div><h3 className="font-bold text-slate-700 text-sm leading-tight">{item.title}</h3><p className="text-[10px] text-slate-400 mt-1 font-mono truncate">Submitted.pdf</p></div>
              </>
            ) : (
              <div className="flex flex-col items-center justify-center h-full text-center">
                <div className="w-10 h-10 rounded-full bg-slate-200 flex items-center justify-center mb-2 group-hover:bg-blue-100 group-hover:text-blue-500 transition-colors"><span className="text-xl font-bold text-slate-400 group-hover:text-blue-500">+</span></div>
                <h3 className="font-bold text-slate-400 text-sm group-hover:text-blue-600 transition-colors">{item.title}</h3>
              </div>
            )}
          </div>
        ))}
      </div>
    </MatrixLayout>
  );
}